const yfData = $('Yahoo Finance Prices').first().json;
const quotes = yfData.quoteResponse?.result || [];
const ethData = $('CoinGecko ETH').first().json;
const ethSGD = ethData.ethereum?.sgd || 2700;
const fxQuote = quotes.find(q => q.symbol === 'USDSGD=X');
const usdsgd = fxQuote?.regularMarketPrice || 1.35;
const prices = {};
quotes.forEach(q => { prices[q.symbol] = q.regularMarketPrice || 0; });

// ── Bobby's positions & cost bases (update if you add more) ──
const positions = [
  { symbol: 'AJBU.SI', name: 'Keppel DC REIT',  qty: 500,       cost: 1.9562,  ccy: 'SGD' },
  { symbol: 'C38U.SI', name: 'CICT',             qty: 500,       cost: 1.9842,  ccy: 'SGD' },
  { symbol: 'HYDD.SI', name: 'BYD HK SDR',       qty: 1600,      cost: 1.9794,  ccy: 'SGD' },
  { symbol: 'J69U.SI', name: 'Frasers Cpt Tr',   qty: 800,       cost: 2.1579,  ccy: 'SGD' },
  { symbol: 'JYEU.SI', name: 'Lendlease REIT',   qty: 900,       cost: 0.595,   ccy: 'SGD' },
  { symbol: 'NVDA',    name: 'NVIDIA',            qty: 3,         cost: 173.99,  ccy: 'USD' },
  { symbol: 'O5RU.SI', name: 'AIMS APAC REIT',   qty: 500,       cost: 1.2775,  ccy: 'SGD' },
  { symbol: 'TSLA',    name: 'Tesla',             qty: 0.3549,    cost: 318.683, ccy: 'USD' }
];

let totalValue = 0, totalPL = 0;
const results = [];

for (const p of positions) {
  const raw      = prices[p.symbol] || 0;
  const priceSGD = p.ccy === 'USD' ? raw * usdsgd : raw;
  const costSGD  = p.ccy === 'USD' ? p.cost * usdsgd : p.cost;
  const value    = p.qty * priceSGD;
  const costTot  = p.qty * costSGD;
  const pl       = value - costTot;
  const plPct    = costTot > 0 ? (pl / costTot) * 100 : 0;
  totalValue += value;
  totalPL    += pl;
  results.push({
    name: p.name, symbol: p.symbol,
    price:    Math.round(raw * 1000) / 1000,
    priceSGD: Math.round(priceSGD * 1000) / 1000,
    value:    Math.round(value * 100) / 100,
    pl:       Math.round(pl * 100) / 100,
    plPct:    Math.round(plPct * 100) / 100
  });
}

// ── ETH ──────────────────────────────────────────────────────
const ethQty     = 0.38935156;
const ethCostSGD = 2560;
const ethValue   = ethQty * ethSGD;
const ethPL      = ethValue - (ethQty * ethCostSGD);
const ethPLPct   = ((ethSGD - ethCostSGD) / ethCostSGD) * 100;
totalValue += ethValue;
totalPL    += ethPL;

// ── BGF World Mining (weekly NAV — hardcoded, update periodically) ──
const bgfUnits    = 1.1624;
const bgfNAV      = 100.16;
const bgfCostUnit = 108.40;
const bgfValSGD   = bgfUnits * bgfNAV * usdsgd;
const bgfPL       = bgfValSGD - (bgfUnits * bgfCostUnit * usdsgd);
const bgfPLPct    = ((bgfNAV - bgfCostUnit) / bgfCostUnit) * 100;
totalValue += bgfValSGD;
totalPL    += bgfPL;

// ── Fullerton SGD Cash (stable money market ~S$1.226/unit) ───
const fulVal  = 95.6727 * 1.226;
const fulPL   = fulVal - 117.00;
totalValue += fulVal;
totalPL    += fulPL;

// ── Build notification message ────────────────────────────────
const plEmoji = totalPL >= 0 ? '📈' : '📉';
const plSign  = totalPL >= 0 ? '+' : '';
const sgTime  = new Date().toLocaleString('en-SG', {
  timeZone: 'Asia/Singapore',
  day: '2-digit', month: 'short', year: 'numeric',
  hour: '2-digit', minute: '2-digit'
});

const lines = results.map(p => {
  const e = p.pl >= 0 ? '🟢' : '🔴';
  const s = p.pl >= 0 ? '+' : '';
  return `${e} ${p.name}: S$${p.value.toFixed(0)} (${s}${p.plPct.toFixed(1)}%)`;
});
lines.push(`${ethPL >= 0 ? '🟢' : '🔴'} ETH: S$${ethValue.toFixed(0)} (${ethPL >= 0 ? '+' : ''}${ethPLPct.toFixed(1)}%)`);
lines.push(`${bgfPL >= 0 ? '🟢' : '🔴'} BGF Mining: S$${bgfValSGD.toFixed(0)} (${bgfPL >= 0 ? '+' : ''}${bgfPLPct.toFixed(1)}%)`);
lines.push(`🔵 Fullerton Cash: S$${fulVal.toFixed(0)}`);

// ── Alerts ────────────────────────────────────────────────────
const alerts = [];
for (const p of results) {
  if (p.plPct <= -10) alerts.push(`🚨 ${p.name} at ${p.plPct.toFixed(1)}%`);
}
if (ethPLPct <= -15) alerts.push(`🚨 ETH at ${ethPLPct.toFixed(1)}%`);
const byd = results.find(r => r.symbol === 'HYDD.SI');
if (byd && (byd.value / totalValue * 100) > 25) {
  alerts.push(`⚠️ BYD is ${(byd.value / totalValue * 100).toFixed(1)}% of portfolio — trim needed`);
}
const alertText = alerts.length > 0
  ? '\n\n🚨 ALERTS:\n' + alerts.join('\n')
  : '\n\n✅ No alerts';

const message = [
  `${plEmoji} Bobby Portfolio • ${sgTime}`,
  `💰 Total: S$${Math.round(totalValue).toLocaleString()}`,
  `${plEmoji} P/L: ${plSign}S$${Math.round(totalPL)}`,
  `💱 USD/SGD: ${usdsgd.toFixed(4)}`,
  '',
  lines.join('\n') + alertText
].join('\n');

return [{ json: {
  message,
  title: `${plEmoji} S$${Math.round(totalValue).toLocaleString()} (${plSign}S$${Math.round(totalPL)})`,
  total_value:  Math.round(totalValue * 100) / 100,
  total_pl:     Math.round(totalPL * 100) / 100,
  usdsgd:       Math.round(usdsgd * 10000) / 10000,
  eth_sgd:      ethSGD,
  alert_count:  alerts.length,
  has_alerts:   alerts.length > 0,
  positions:    results,
  timestamp:    new Date().toISOString()
}}];
